package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetAutoFlush_DefaultConstructorValue() {
        CSVFormat format = CSVFormat.DEFAULT;
        boolean autoFlush = format.getAutoFlush();
        assertFalse(autoFlush);
    }

    @Test
    void testGetAutoFlush_WithAutoFlushTrue() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withAutoFlush(true);
        assertTrue(format.getAutoFlush());

        Field autoFlushField = CSVFormat.class.getDeclaredField("autoFlush");
        autoFlushField.setAccessible(true);
        assertTrue(autoFlushField.getBoolean(format));
    }

    @Test
    void testGetAutoFlush_WithAutoFlushFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withAutoFlush(false);
        assertFalse(format.getAutoFlush());
    }
}
